const fs = require('fs');
const _ = require('lodash');

const glob = require('glob');

const CleanCSS = require('clean-css');
/**
 * css 파일들을 압축한다.
 */
class CssMinifierPlugin{

    constructor({
    } = {}){}
    apply(compiler){

        compiler.plugin('done', function(){

            const outputPath = this.outputPath;

            const files = glob.sync(`${outputPath}/**/*.css`);

            _.forEach(files, v => {

                const source = fs.readFileSync(v, 'utf-8');
                const output = new CleanCSS({compatibility: 'ie9'}).minify(source);

                fs.writeFileSync(v, output.styles);
            });
        });
    };
}

module.exports = CssMinifierPlugin;